// Extract the array of users with their sessions
const response = $input.first().json;
const usersData = response.data || [];

// Return each user as a separate item for the loop
return usersData.map(user => ({
  json: {
    userId: user.userId,
    userName: user.userName,
    userEmail: user.userEmail,
    sessionCount: user.sessionCount,
    topics: user.context.topics,
    allKeyConcepts: user.context.allKeyConcepts,
    totalDuration: user.context.totalDuration,
    summaries: user.context.summaries,
    sessions: user.sessions
  }
}));

// Build the AI prompt to generate a comprehensive weekly test
const item = $input.first().json;

const prompt = `You are an expert educator. Based on the following study sessions from this week, create a comprehensive weekly test.

STUDENT: ${item.userName}
NUMBER OF SESSIONS: ${item.sessionCount}
TOTAL STUDY TIME: ${item.totalDuration} minutes

TOPICS COVERED:
${item.topics.map((t, i) => `${i+1}. ${t}`).join('\n')}

KEY CONCEPTS:
${item.allKeyConcepts.join(', ')}

SESSION DETAILS:
${item.summaries}

CREATE A TEST WITH EXACTLY 15 QUESTIONS:
- 10 Multiple Choice Questions (MCQ) with 4 options each
- 5 Short Answer Questions

IMPORTANT: Return ONLY valid JSON in this exact format, no other text:
{
  "title": "Weekly Test - [Date Range]",
  "questions": [
    {
      "id": 1,
      "type": "mcq",
      "question": "Your question here?",
      "options": ["A) Option 1", "B) Option 2", "C) Option 3", "D) Option 4"],
      "correct_answer": "A",
      "topic": "Topic name",
      "difficulty": "easy|medium|hard",
      "explanation": "Brief explanation of the answer"
    },
    {
      "id": 11,
      "type": "short_answer",
      "question": "Your question here?",
      "correct_answer": "Expected answer",
      "topic": "Topic name",
      "difficulty": "easy|medium|hard",
      "explanation": "Brief explanation"
    }
  ]
}`;

return [{
  json: {
    ...item,
    aiPrompt: prompt
  }
}];

