// Parse the AI response and prepare test data
const item = $('Build AI Prompt').first().json;
let aiResponse;

try {
  const raw = $input.first().json;
  // Groq uses OpenAI format
  if (raw.choices) {
    const content = raw.choices[0].message.content;
    aiResponse = JSON.parse(content);
  } else {
    aiResponse = raw;
  }
} catch (e) {
  // Fallback: generate a basic test from session data
  const questions = [];
  const concepts = item.allKeyConcepts;

  for (let i = 0; i < Math.min(15, concepts.length); i++) {
    if (i < 10) {
      questions.push({
        id: i + 1,
        type: 'mcq',
        question: `Which of the following best describes "${concepts[i]}"?`,
        options: [
          `A) A fundamental concept in ${item.topics[0] || 'this subject'}`,
          `B) An advanced technique used in modern systems`,
          `C) A deprecated methodology no longer in use`,
          `D) None of the above`
        ],
        correct_answer: 'A',
        topic: item.topics[i % item.topics.length] || 'General',
        difficulty: 'medium',
        explanation: `${concepts[i]} is a key concept covered in the sessions.`
      });
    } else {
      questions.push({
        id: i + 1,
        type: 'short_answer',
        question: `Explain the concept of "${concepts[i]}" in your own words.`,
        correct_answer: `${concepts[i]} - as discussed in the session on ${item.topics[i % item.topics.length]}`,
        topic: item.topics[i % item.topics.length] || 'General',
        difficulty: 'medium',
        explanation: 'Review the session notes for a comprehensive understanding.'
      });
    }
  }

  aiResponse = {
    title: `Weekly Test - ${new Date().toLocaleDateString()}`,
    questions: questions
  };
}

// Calculate expiry (6 hours from now)
const now = new Date();
const expiresAt = new Date(now.getTime() + 6 * 60 * 60 * 1000);

return [{
  json: {
    userId: item.userId,
    userName: item.userName,
    userEmail: item.userEmail,
    title: aiResponse.title || `Weekly Test - ${now.toLocaleDateString()}`,
    questions: aiResponse.questions || [],
    totalQuestions: (aiResponse.questions || []).length,
    createdAt: now.toISOString(),
    expiresAt: expiresAt.toISOString()
  }
}];

// Log the result for each user
const testData = $('Parse AI Response').first().json;
const saveResult = $input.first().json;

console.log(`✅ Test created for ${testData.userName}`);
console.log(`   📝 Title: ${testData.title}`);
console.log(`   ❓ Questions: ${testData.totalQuestions}`);
console.log(`   ⏰ Expires: ${testData.expiresAt}`);

return [{
  json: {
    status: 'success',
    userName: testData.userName,
    userEmail: testData.userEmail,
    testTitle: testData.title,
    totalQuestions: testData.totalQuestions,
    expiresAt: testData.expiresAt,
    testId: saveResult.data?.id || 'unknown',
    message: `Weekly test created for ${testData.userName} with ${testData.totalQuestions} questions. Expires at ${testData.expiresAt}`
  }
}];
